import React, { useRef, useEffect, useState } from 'react';
import {
  AppBar, Toolbar, Typography, IconButton, Drawer, List, ListItem, ListItemText, Divider, Box, Slider, Input, Button, Modal
} from '@mui/material';
import {
  Brush as BrushIcon,
  Undo as UndoIcon,
  Redo as RedoIcon,
  Delete as DeleteIcon,
  ColorLens as ColorLensIcon
} from '@mui/icons-material';

const shapeDefinitions = {
  select: { text: 'Select Figure...', params: [] },
  point: { text: 'POINT', params: [ {name:'x', label:'X:'}, {name:'y', label:'Y:'} ] },
  line: { text: 'LINE', params: [ {name:'x1', label:'X1:'}, {name:'y1', label:'Y1:'}, {name:'x2', label:'X2:'}, {name:'y2', label:'Y2:'} ] },
  circle: { text: 'CIRCLE', params: [ {name:'centerX', label:'Center X:'}, {name:'centerY', label:'Center Y:'}, {name:'radius', label:'Radius'} ] },
  rectangle: { text: 'RECTANGLE', params: [ {name:'centerX', label:'Center X:'}, {name:'centerY', label:'Center Y:'}, {name:'width', label:'Width'}, {name:'height', label:'Height'} ] },
  triangle: { text: 'TRIANGLE', params: [ {name:'x1', label:'X1:'}, {name:'y1', label:'Y1:'}, {name:'x2', label:'X2:'}, {name:'y2', label:'Y2:'}, {name:'x3', label:'X3:'}, {name:'y3', label:'Y3:'} ] },
  ellipse: { text: 'ELLIPSE', params: [ {name:'centerX', label:'Center X:'}, {name:'centerY', label:'Center Y:'}, {name:'radiusX', label:'Radius X:'}, {name:'radiusY', label:'Radius Y:'} ] },
};

const defaultShape = 'select';

const style = {
  drawer: { width: 300, flexShrink: 0 },
  drawerPaper: { width: 300, boxSizing: 'border-box', padding: 2 },
  canvas: { border: '1px solid #e5e7eb', background: '#fff', borderRadius: 6 },
  codePreview: { width: 350, padding: 2, background: '#f9fafb', borderLeft: '1px solid #d1d5db', height: '100%' },
  modal: { display: 'flex', alignItems: 'center', justifyContent: 'center' },
  modalContent: { background: '#fff', padding: 24, borderRadius: 8, maxWidth: 600, width: '90%' },
};

function App() {
  const canvasRef = useRef(null);
  const [figures, setFigures] = useState([]);
  const [redoStack, setRedoStack] = useState([]);
  const [selectedShape, setSelectedShape] = useState(defaultShape);
  const [shapeParams, setShapeParams] = useState({});
  const [color, setColor] = useState('#4f46e5');
  const [lineWidth, setLineWidth] = useState(2);
  const [drawerOpen, setDrawerOpen] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [mouseCoords, setMouseCoords] = useState({ x: '--', y: '--' });

  // Draw grid and axes
  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    const width = canvas.width;
    const height = canvas.height;
    ctx.clearRect(0, 0, width, height);
    ctx.fillStyle = '#fff';
    ctx.fillRect(0, 0, width, height);
    // Grid
    ctx.save();
    ctx.strokeStyle = '#e0e0e0';
    ctx.lineWidth = 0.5;
    const gridSpacing = 20;
    for (let x = 0; x <= width; x += gridSpacing) {
      ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, height); ctx.stroke();
    }
    for (let y = 0; y <= height; y += gridSpacing) {
      ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(width, y); ctx.stroke();
    }
    // Axes
    ctx.strokeStyle = '#888';
    ctx.lineWidth = 1.5;
    ctx.beginPath(); ctx.moveTo(width/2, 0); ctx.lineTo(width/2, height); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(0, height/2); ctx.lineTo(width, height/2); ctx.stroke();
    ctx.restore();
  }, []);

  // Mouse coordinate display
  const handleMouseMove = (e) => {
    const rect = canvasRef.current.getBoundingClientRect();
    const x = Math.round(e.clientX - rect.left - canvasRef.current.width/2);
    const y = Math.round(canvasRef.current.height/2 - (e.clientY - rect.top));
    setMouseCoords({ x, y });
  };
  const handleMouseLeave = () => setMouseCoords({ x: '--', y: '--' });

  // Dynamic input fields for shape params
  const renderShapeInputs = () => {
    const def = shapeDefinitions[selectedShape];
    if (!def || !def.params.length) return null;
    return def.params.map(param => (
      <Box key={param.name} sx={{ mb: 1 }}>
        <Input
          type="number"
          placeholder={param.label}
          value={shapeParams[param.name] || ''}
          onChange={e => setShapeParams({ ...shapeParams, [param.name]: e.target.value })}
          sx={{ width: '100%' }}
        />
      </Box>
    ));
  };

  return (
    <Box sx={{ height: '100vh', display: 'flex', flexDirection: 'column' }}>
      <AppBar position="static">
        <Toolbar>
          <Typography variant="h6" sx={{ flexGrow: 1 }}>Draze - Where Shapes Take Form</Typography>
          <Button color="inherit" onClick={() => setModalOpen(true)}>User Manual</Button>
          <IconButton color="inherit" onClick={() => setDrawerOpen(true)}><BrushIcon /></IconButton>
          <IconButton color="inherit"><UndoIcon /></IconButton>
          <IconButton color="inherit"><RedoIcon /></IconButton>
          <IconButton color="inherit"><DeleteIcon /></IconButton>
        </Toolbar>
      </AppBar>
      <Box sx={{ display: 'flex', flexGrow: 1, minHeight: 0 }}>
        <Drawer
          variant="persistent"
          open={drawerOpen}
          sx={style.drawer}
          PaperProps={{ sx: style.drawerPaper }}
        >
          <Typography variant="subtitle1" sx={{ mt: 2, mb: 1 }}>TOOLS</Typography>
          <select
            value={selectedShape}
            onChange={e => { setSelectedShape(e.target.value); setShapeParams({}); }}
            style={{ width: '100%', marginBottom: 12, padding: 8 }}
          >
            {Object.entries(shapeDefinitions).map(([key, def]) => (
              <option key={key} value={key}>{def.text}</option>
            ))}
          </select>
          {renderShapeInputs()}
          <Divider sx={{ my: 2 }} />
          <Typography variant="subtitle2">INFO & PROPERTIES</Typography>
          <Box sx={{ mb: 1, mt: 1 }}>
            <span>X: {mouseCoords.x}</span> <span style={{ marginLeft: 12 }}>Y: {mouseCoords.y}</span>
          </Box>
          <Box sx={{ mb: 2 }}>
            <label>Choose Colour:</label>
            <Input type="color" value={color} onChange={e => setColor(e.target.value)} sx={{ width: '100%' }} />
          </Box>
          <Box sx={{ mb: 2 }}>
            <label>Choose Width: <span>{lineWidth}</span></label>
            <Slider min={1} max={10} step={0.5} value={lineWidth} onChange={(_, v) => setLineWidth(v)} />
          </Box>
        </Drawer>
        <Box sx={{ flexGrow: 1, display: 'flex', flexDirection: 'row', minHeight: 0 }}>
          <Box sx={{ flex: 3, display: 'flex', alignItems: 'center', justifyContent: 'center', bgcolor: '#f9fafb' }}>
            <canvas
              ref={canvasRef}
              width={600}
              height={450}
              style={style.canvas}
              onMouseMove={handleMouseMove}
              onMouseLeave={handleMouseLeave}
            />
          </Box>
          <Box sx={style.codePreview}>
            <Typography variant="subtitle2" sx={{ mb: 1 }}>Figure Data (JSON)</Typography>
            <textarea
              value={figures.length ? JSON.stringify(figures, null, 2) : ''}
              readOnly
              style={{ width: '100%', height: '90%', fontFamily: 'monospace', fontSize: 14, background: '#f9fafb', border: '1px solid #e5e7eb', borderRadius: 6 }}
              placeholder="Drawn figures data will appear here..."
            />
          </Box>
        </Box>
      </Box>
      <Modal open={modalOpen} onClose={() => setModalOpen(false)} sx={style.modal}>
        <Box sx={style.modalContent}>
          <Typography variant="h6">User Manual</Typography>
          <Typography variant="body2" sx={{ mt: 2 }}>
            Welcome to Draze! This tool allows you to draw various geometric shapes on a canvas.<br /><br />
            <b>Keyboard Shortcuts:</b><br />
            Ctrl+D: Draw the selected figure.<br />
            Ctrl+Z: Undo the last action.<br />
            Ctrl+Y: Redo the last undone action.<br />
            Ctrl+C: Clear all figures from the canvas.<br /><br />
            <b>Basic Usage:</b><br />
            1. Select a figure type from the "Select Shape" dropdown.<br />
            2. Enter the required dimensions.<br />
            3. Choose a color and line thickness.<br />
            4. Click Draw or press Ctrl+D to draw.<br />
            5. View JSON in the "Figure Data" panel.<br />
            6. Use Undo, Redo, and Clear as needed.<br />
          </Typography>
          <Button onClick={() => setModalOpen(false)} sx={{ mt: 2 }}>Close</Button>
        </Box>
      </Modal>
    </Box>
  );
}

export default App;
